run {
    // Influencers and regular users exist, following is only between distinct users.
    some i1, i2: Influencer | i1 != i2 and i1 in i2.follows
    some u: User - Influencer // Ensure there's also a non-influencer user
    all u: User | u not in u.follows
} for 4 expect 1

run {
    // A chain of following exists, but no self-loops.
    #User >= 3
    let u1 = one User, u2 = one User - u1, u3 = one User - (u1 + u2) {
        u1 in u2.follows
        u2 in u3.follows
    }
    all u: User | u not in u.follows
} for 4 expect 1

run {
    // Multiple users exist, and at least one of them follows themselves.
    #User >= 2
    some u1: User | u1 in u1.follows
    some u2: User | u2 != u1 // Ensure there's another user for context
    all u: User | u not in u.follows
} for 4 expect 0

