} for 4 expect 0

parse:
run P1_AllAdsSeen {
  some u: User, some a: Ad {
    // A user posts an ad.
    u.posts = a
    // All users see this ad.
    all u_all: User | a in u_all.sees
    // No non-ads exist in this scenario, simplifying the second part of the requirement.
    no Photo - Ad
  }
} for 4 expect 1

run P3_MixedScenarioSimple {
  some disj u1, u2, u3: User {
    // U1 follows U2.
    u1.follows = u2
    // U2 posts a non-ad photo P.
    one p: Photo - Ad { u2.posts = p }
    // U3 posts an ad A.
    one a: Ad { u3.posts = a }

    // U1 sees Ad A (posted by U3) and non-Ad P (posted by followed U2).
    u1.sees = a + p
    // U2 sees Ad A (posted by U3), but not P (as U2 doesn't follow self).
    u2.sees = a
    // U3 sees Ad A (posted by U3), but not P (as U3 doesn't follow U2).
    u3.sees = a

    // Ensure other users (if any) only see ads.
    all u: User - (u1+u2+u3) | u.sees = a
    // Ensure no other photos are posted besides A and P.
    all photo_other: Photo - (a + p) | photo_other not in (User.posts)
  }
  Req
} for 4 expect 1

run P5_NonAdOwnPostNotSeen {
  some disj u1, u2: User {
    some p1, p2: Photo - Ad {
      // U1 posts P1, U2 posts P2.
      u1.posts = p1
      u2.posts = p2
      // U1 follows U2, and U2 follows U1 (mutual following).
      u1.follows = u2
      u2.follows = u1

      // U1 sees P2 (from U2 whom U1 follows), but NOT P1 (since U1 doesn't follow self).
      u1.sees = p2
      // U2 sees P1 (from U1 whom U2 follows), but NOT P2 (since U2 doesn't follow self).
      u2.sees = p1
    }
    // No ads exist in this scenario.
    no Ad
    // Other users, if any, don't post, see, or follow.
    all u: User - (u1+u2) | u.posts = none and u.sees = none and u.follows = none
  }
  Req
} for 4 expect 1

run N1_AdNotSeen {
  some disj u1, u2: User {
    some a: Ad {
      // User u1 posts an ad a.
      u1.posts = a
      // But user u2 does NOT see this ad, violating "Users can see ads posted by everyone".
      a not in u2.sees
    }
    // Ensure all other users (except u2) see the ad for a focused violation.
    all u: User - u2 | a in u.sees
    // No non-ads for simplicity.
    no Photo - Ad
  }
  Req
} for 4 expect 0

run N2_NonAdSeenFromUnfollowed {
