    // Violation 2: Non-ad seen from unfollowed user.
    some p: Photo - Ad {
      u2.posts = p
      p in u3.sees // U3 sees non-ad P posted by U2.
      u3.follows = none // U3 follows nobody, thus not U2.
      u2.sees = none // U2 doesn't see its own non-ad to avoid accidental validity.
